// Response is an array
const session = Array.isArray($input.item.json) ? $input.item.json[0] : $input.item.json;

let devinResponse = '';
let attachmentUrl = '';

if (session.messages && session.messages.length > 0) {
  const devinMsgs = session.messages.filter(m => m.type === 'devin_message');
  if (devinMsgs.length > 0) {
    const last = devinMsgs[devinMsgs.length - 1];
    const msgText = last.message || '';

    // Parse attachment reference from message
    const attachMatch = msgText.match(/ATTACHMENT:(\{.*\})/);
    if (attachMatch) {
      try {
        const attachment = JSON.parse(attachMatch[1]);
        attachmentUrl = attachment.url || '';
      } catch(e) {}
      devinResponse = msgText.replace(/\s*ATTACHMENT:\{.*\}/, '').trim();
    } else {
      devinResponse = msgText;
    }
  }
}

if (!devinResponse && !attachmentUrl) {
  devinResponse = '(Devin Antwort nicht verfügbar — Status: ' + (session.status_enum || session.status || 'unbekannt') + ')';
}

return [{ json: { devinResponse, attachmentUrl, sessionStatus: session.status_enum } }];

const extractData = $('Devin: Extract Response').item.json;
const attachmentContent = $('Devin: Fetch Attachment').item.json;

// Attachment response may be plain text/markdown
const attachmentText = typeof attachmentContent === 'string'
  ? attachmentContent
  : (attachmentContent.body || attachmentContent.data || JSON.stringify(attachmentContent));

// Use attachment if available, otherwise fallback to message text
const devinResponse = attachmentText && attachmentText.length > 10
  ? attachmentText
  : extractData.devinResponse;

return [{ json: { devinResponse } }];
